static void
initpath(const char *pathstr)
{
	char *copy, *tok, *saveptr;
	int count, i;

	if (pathstr == NULL) {
		path_dirs = NULL;
		path_ndirs = 0;
		return;
	}

	// Count the number of directories (colons + 1).
	count = 1;
	for (i = 0; pathstr[i] != '\0'; i++) {
		if (pathstr[i] == ':')
			count++;
	}

	path_dirs = malloc(count * sizeof(char *));
	if (path_dirs == NULL)
		unix_error("malloc error");

	copy = strdup(pathstr);
	if (copy == NULL)
		unix_error("strdup error");

	path_ndirs = 0;
	tok = strtok_r(copy, ":", &saveptr);
	// Handle leading colon (empty first token means current dir)
	if (pathstr[0] == ':') {
		path_dirs[path_ndirs++] = strdup("");
	}
	while (tok != NULL) {
		path_dirs[path_ndirs++] = strdup(tok);
		tok = strtok_r(NULL, ":", &saveptr);
	}
	// Handle trailing colon (empty last token means current dir)
	if (pathstr[0] != '\0' && pathstr[strlen(pathstr) - 1] == ':') {
		path_dirs[path_ndirs++] = strdup("");
	}
	free(copy);
}

