static void
eval(const char *cmdline)
{
	char *argv[MAXARGS];
	char execpath[MAXLINE];
	bool bg;
	pid_t pid;
	sigset_t mask_chld, prev_mask;
	int i;

	bg = parseline(cmdline, argv);

	// Ignore empty lines.
	if (argv[0] == NULL)
		return;

	// If it's a built-in command, execute it directly.
	if (builtin_cmd(argv))
		return;

	// Determine the executable path.
	// If the name contains '/', treat as path directly.
	if (strchr(argv[0], '/') != NULL || path_dirs == NULL) {
		strncpy(execpath, argv[0], MAXLINE - 1);
		execpath[MAXLINE - 1] = '\0';
	} else {
		// Search each directory in PATH.
		bool found = false;
		for (i = 0; i < path_ndirs; i++) {
			if (path_dirs[i][0] == '\0') {
				// Empty string = current directory.
				snprintf(execpath, MAXLINE, "./%s", argv[0]);
			} else {
				snprintf(execpath, MAXLINE, "%s/%s",
				    path_dirs[i], argv[0]);
			}
			if (access(execpath, X_OK) == 0) {
				found = true;
				break;
			}
		}
		if (!found) {
			printf("%s: Command not found\n", argv[0]);
			return;
		}
	}

	// Block SIGCHLD before fork to avoid race condition.
	sigemptyset(&mask_chld);
	sigaddset(&mask_chld, SIGCHLD);
	sigprocmask(SIG_BLOCK, &mask_chld, &prev_mask);

	if ((pid = fork()) < 0)
		unix_error("fork error");

	if (pid == 0) {
		// Child process.
		// Put child in its own process group.
		setpgid(0, 0);
		// Unblock SIGCHLD in child.
		sigprocmask(SIG_SETMASK, &prev_mask, NULL);
		// Execute the program.
		execve(execpath, argv, environ);
		// If execve returns, command was not found/executable.
		printf("%s: %s\n", argv[0], strerror(errno));
		exit(1);
	}

	// Parent process: add job to list before unblocking SIGCHLD.
	int state = bg ? BG : FG;
	addjob(jobs, pid, state, cmdline);

	// Unblock SIGCHLD.
	sigprocmask(SIG_SETMASK, &prev_mask, NULL);

	if (bg) {
		// Print background job info.
		printf("[%d] (%d) %s", pid2jid(pid), (int)pid, cmdline);
	} else {
		// Wait for foreground job to complete.
		waitfg(pid);
	}
}

