static void
do_bgfg(char **argv)
{
	JobP job;
	char *arg;
	int jid;
	pid_t pid;
	bool is_fg;

	if (argv[1] == NULL) {
		printf("%s command requires PID or %%jobid argument\n", argv[0]);
		return;
	}

	arg = argv[1];
	is_fg = (strcmp(argv[0], "fg") == 0);

	if (arg[0] == '%') {
		// JID argument.
		char *endptr;
		jid = (int)strtol(arg + 1, &endptr, 10);
		if (*endptr != '\0' || endptr == arg + 1) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		job = getjobjid(jobs, jid);
		if (job == NULL) {
			printf("%%%d: No such job\n", jid);
			return;
		}
	} else {
		// PID argument.
		char *endptr;
		pid = (pid_t)strtol(arg, &endptr, 10);
		if (*endptr != '\0' || endptr == arg) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		job = getjobpid(jobs, pid);
		if (job == NULL) {
			printf("(%d): No such process\n", (int)pid);
			return;
		}
	}

	// Send SIGCONT to the entire process group.
	kill(-(job->pid), SIGCONT);

	if (is_fg) {
		job->state = FG;
		waitfg(job->pid);
	} else {
		job->state = BG;
		printf("[%d] (%d) %s", job->jid, (int)job->pid, job->cmdline);
	}
}

