static void
waitfg(pid_t pid)
{
	sigset_t mask_chld, prev_mask;

	// Block SIGCHLD before checking condition to eliminate the race
	// between the check and sigsuspend.
	sigemptyset(&mask_chld);
	sigaddset(&mask_chld, SIGCHLD);
	sigprocmask(SIG_BLOCK, &mask_chld, &prev_mask);

	// sigsuspend atomically restores prev_mask (unblocking SIGCHLD) and waits.
	while (fgpid(jobs) == pid)
		sigsuspend(&prev_mask);

	// Restore original mask.
	sigprocmask(SIG_SETMASK, &prev_mask, NULL);
}

